INSERT INTO training_records (employee_id, training_type_id, completion_date, source)
SELECT e.id, sr.training_type_id, sr.completion_date, 'access'
FROM source_rows sr
JOIN employees e ON lower(e.last_name) = lower(sr.last_name) AND lower(e.first_name) = lower(sr.first_name)
ON CONFLICT (employee_id, training_type_id, completion_date) DO NOTHING;